+            BaselineScenarioDomain::Runtime,
+            BaselineScenarioOutcome::CanonicalFailure,
+            "runtime_lane",
+            "runtime_guard_abort",
+            Some("FE-RGC-053A-RUNTIME-0001"),
+        ),
+        BaselineE2eScenario::new(
+            "rgc-053a-module-happy",
+            "module-smoke-happy",
+            BaselineScenarioDomain::Module,
