+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum ArtifactValidationErrorCode {
+    MissingArtifact,
+    InvalidManifestJson,
+    InvalidEventJson,
+    MissingRequiredField,
+    CorrelationMismatch,
+    CountMismatch,
